// n8n Function node
// Input: item.json.trancript
// Output: { transcriptContents: string }

function formatAsCircleback(arr) {
  if (!Array.isArray(arr) || arr.length === 0) return 'No transcript available';
  return arr.map(t => {
    const sec = Math.max(0, Math.floor(Number(t?.timestamp || 0)));
    const hh = String(Math.floor(sec / 3600)).padStart(2, '0');
    const mm = String(Math.floor((sec % 3600) / 60)).padStart(2, '0');
    const ss = String(sec % 60).padStart(2, '0');
    const speaker = (t?.speaker ?? 'Unknown').toString();
    const text = (t?.text ?? '').toString();
    return `[${hh}:${mm}:${ss} ${speaker}] ${text}`;
  }).join('\n');
}

function toTranscriptContents(anyVal) {
  if (typeof anyVal === 'string') {
    return anyVal || 'No transcript available';
  }
  if (Array.isArray(anyVal)) {
    // Assume Circleback format
    return formatAsCircleback(anyVal);
  }
  try {
    return JSON.stringify(anyVal);
  } catch {
    return String(anyVal ?? 'No transcript available');
  }
}

const out = [];
for (const item of $input.all()) {
  const t = item.json.body?.transcript || item.json.transcript || item.json.notes;
  if (item.json.body?.transcript)
    delete item.json.body.transcript
  out.push({
    json: {
      ...item.json,
      transcriptContents: toTranscriptContents(t),
    }
  });
}
return out;

