/**
 * n8n Code / Function node
 * Replaces {DECISION_LOG} in meeting_notes_markdown with a formatted Markdown table.
 */

function escapeMD(s = "") {
  // Escape pipes and convert newlines in cell values to <br>
  return String(s)
    .replace(/\|/g, "\\|")
    .replace(/\r?\n/g, " <br> ")
    .trim();
}

function formatDate(d) {
  if (!d) return "";
  const iso = /^\d{4}-\d{2}-\d{2}$/;
  if (iso.test(d)) return d;
  const parsed = new Date(d);
  if (!isNaN(parsed)) {
    const y = parsed.getFullYear();
    const m = String(parsed.getMonth() + 1).padStart(2, "0");
    const day = String(parsed.getDate()).padStart(2, "0");
    return `${y}-${m}-${day}`;
  }
  return escapeMD(d);
}

function buildDecisionTable(decisions = []) {
  const header =
    "| **Decision** | **Owner** | **Date** | **Risk if Wrong** | **Follow-on Actions** |\n" +
    "|---|---|---|---|---|";

  const rows = decisions.map(d => {
    const title   = escapeMD(d.title);
    const owner   = escapeMD(d.owner);
    const date    = formatDate(d.date);
    const risk    = escapeMD(d.risk);
    const actions = escapeMD(d.actions);

    return `| ${title} | ${owner} | ${date} | ${risk} | ${actions} |`;
  });

  return [header, ...rows].join("\n");
}

return items.map(item => {
  const obj = item.json ?? {};
  const md  = obj.meeting_notes_markdown || "";
  const decisions = Array.isArray(obj.decisions) ? obj.decisions : [];

  const table = buildDecisionTable(decisions);

  let outputMD = md;

  if (md.includes("{DECISION_LOG}")) {
    outputMD = md.replace("{DECISION_LOG}", table);
  } else {
    // fallback if merge field missing
    const headingRegex = /(##\s*2\)\s*Key Decisions[^\n]*\n)/i;
    if (headingRegex.test(md)) {
      outputMD = md.replace(headingRegex, `$1\n${table}\n`);
    } else {
      outputMD = `${md}\n\n${table}`;
    }
  }

  return {
    json: {
      ...obj,
      decisions: undefined,
      meeting_notes_markdown: outputMD,
    },
  };
});
